#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[1000];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        int leaders[1000];
        int cnt = 0;
        int maxFromRight = arr[n - 1];
        leaders[cnt++] = maxFromRight; // rightmost element
        for (int i = n - 2; i >= 0; --i) {
            if (arr[i] > maxFromRight) {
                maxFromRight = arr[i];
                leaders[cnt++] = maxFromRight;
            }
        }
        // print in reverse to get left‑to‑right order
        for (int i = cnt - 1; i >= 0; --i) {
            printf("%d", leaders[i]);
            if (i) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

