  const n = parseInt(data[idx++], 10);
  const arr = [];
  for (let i = 0; i < n; i++) arr.push(parseInt(data[idx++], 10));
  const leaders = [];
  let maxFromRight = arr[n - 1];
  leaders.push(maxFromRight);
  for (let i = n - 2; i >= 0; i--) {
    if (arr[i] > maxFromRight) {
      maxFromRight = arr[i];
      leaders.push(maxFromRight);
    }
  }
  outputs.push(leaders.reverse().join(' '));
}
